      `}</style>
    </div>
  );
};

payload.text:
C'est une excellente idée pour centraliser les données et permettre la collaboration.

Comme il s'agit d'une application React (côté client) et que nous ne pouvons pas accéder directement à votre Google Sheet sans exposer vos clés de sécurité, nous devons utiliser un script intermédiaire **Google Apps Script**.

Voici la procédure en 2 étapes :

### Étape 1 : Mettre en place le Script Google (Obligatoire)

1.  Ouvrez votre fichier Google Sheet : [Votre Lien](https://docs.google.com/spreadsheets/d/1xg-TQa7wvMgPI-gohGQg6HnYXbED9ZvdjuSIDRxmxx0/edit?usp=sharing)
2.  Allez dans le menu **Extensions** > **Apps Script**.
3.  Effacez tout le code existant et collez le code ci-dessous. Ce script va transformer votre Sheet en base de données pour l'application.

```javascript
function doGet() {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName('Suivi');
  if (!sheet) return ContentService.createTextOutput(JSON.stringify([])).setMimeType(ContentService.MimeType.JSON);

  const data = sheet.getDataRange().getValues();
  const headers = data.shift(); // Enlever l'en-tête

  // On récupère la colonne "JSON_DATA" (dernière colonne cachée habituellement)
  const documents = data.map(row => {
    try {
      // La colonne 8 (index 7) contient l'objet complet
      return JSON.parse(row[7]); 
    } catch (e) { return null; }
  }).filter(doc => doc !== null);

  return ContentService.createTextOutput(JSON.stringify(documents)).setMimeType(ContentService.MimeType.JSON);
}

function doPost(e) {
  const lock = LockService.getScriptLock();
  lock.tryLock(10000);

  try {
    const sheetName = 'Suivi';
    let sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(sheetName);

    if (!sheet) {
      sheet = SpreadsheetApp.getActiveSpreadsheet().insertSheet(sheetName);
      // Créer les en-têtes
      sheet.appendRow(['ID', 'Lot', 'Poste', 'Code', 'Nom', 'Indice', 'Statut', 'JSON_DATA']);
      sheet.setFrozenRows(1);
    }

    const newDocs = JSON.parse(e.postData.contents);

    // On efface les anciennes données (sauf en-têtes) pour resynchroniser
    const lastRow = sheet.getLastRow();
    if (lastRow > 1) {
      sheet.getRange(2, 1, lastRow - 1, 8).clearContent();
    }

    const rows = newDocs.map(doc => {
      // On prend la dernière révision pour les colonnes visibles
      const lastRev = doc.revisions && doc.revisions.length > 0 
        ? doc.revisions[doc.currentRevisionIndex || (doc.revisions.length - 1)] 
        : { index: '00', status: 'PENDING' };

      return [
        doc.id,
        doc.lot,
        doc.poste,
        doc.code,
        doc.name,
        lastRev.index,
        lastRev.status,
        JSON.stringify(doc) // On sauvegarde tout l'objet ici pour ne rien perdre
      ];
    });

    if (rows.length > 0) {
      sheet.getRange(2, 1, rows.length, 8).setValues(rows);
    }

    return ContentService.createTextOutput(JSON.stringify({ result: 'success', count: rows.length })).setMimeType(ContentService.MimeType.JSON);

  } catch (e) {
    return ContentService.createTextOutput(JSON.stringify({ result: 'error', error: e.toString() })).setMimeType(ContentService.MimeType.JSON);
  } finally {
    lock.releaseLock();
  }
}
```

4.  Cliquez sur **Déployer** (bouton bleu en haut à droite) > **Nouveau déploiement**.
5.  Cliquez sur la roue dentée à côté de "Sélectionner le type" > **Application Web**.
6.  Configuration :
    *   Description : `API GED`
    *   Exécuter en tant que : **Moi** (votre email).
    *   Qui peut accéder : **Tout le monde** (C'est crucial pour que l'app React puisse y accéder sans login complexe).
7.  Cliquez sur **Déployer**.
8.  **Copiez l'URL de l'application Web** (elle commence par `https://script.google.com/macros/s/...`).

### Étape 2 : Mise à jour de l'application React

Je vais maintenant modifier l'application pour :
1.  Ajouter un service de connexion à Google Sheets.
2.  Ajouter un champ dans les "Paramètres" pour coller l'URL que vous venez de générer.
3.  Synchroniser automatiquement les données.

