import { BTPDocument } from '../types';

// Récupérer l'URL configurée dans le localStorage
const getApiUrl = () => {
    const settings = localStorage.getItem('btp-app-settings');
    if (settings) {
        const parsed = JSON.parse(settings);
        return parsed.googleScriptUrl || null;
    }
    return null;
};

export const fetchDocumentsFromSheet = async (): Promise<BTPDocument[] | null> => {
    const url = getApiUrl();
    if (!url) return null;

    try {
        const response = await fetch(url);
        const data = await response.json();
        // Le script retourne un tableau de documents
        return Array.isArray(data) ? data : [];
    } catch (error) {
        console.error("Erreur chargement Google Sheet:", error);
        return null;
    }
};

export const saveDocumentsToSheet = async (documents: BTPDocument[]): Promise<boolean> => {
    const url = getApiUrl();
    if (!url) return false;

    try {
        // On utilise 'no-cors' car souvent Apps Script ne renvoie pas les bons headers CORS pour un POST simple,
        // mais l'action s'exécute quand même côté serveur. 
        // Cependant, pour du POST de données JSON, la méthode standard est sendBeacon ou fetch.

        await fetch(url, {
            method: 'POST',
            body: JSON.stringify(documents)
        });
        return true;
    } catch (error) {
        console.error("Erreur sauvegarde Google Sheet:", error);
        return false;
    }
};

