export default function App() {
  const [activeTab, setActiveTab] = useState('overview'); // Default to overview (Dashboard)
  const [initialDocFilter, setInitialDocFilter] = useState<ApprovalStatus | 'ALL'>('ALL');
  const [bordereauSelectedDocs, setBordereauSelectedDocs] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);
  const [syncing, setSyncing] = useState(false);

  const [documents, setDocuments] = useState<BTPDocument[]>([]);
  const [isInitialized, setIsInitialized] = useState(false);

  // 1. Initial Load: Try Sheet first, fallback to LocalStorage/Init
  useEffect(() => {
      const initData = async () => {
          setLoading(true);

          // Try fetching from Google Sheet
          const sheetDocs = await fetchDocumentsFromSheet();

          if (sheetDocs && sheetDocs.length > 0) {
              setDocuments(sheetDocs);
          } else {
              // Fallback to LocalStorage
              const localSaved = localStorage.getItem('btp-docs');
              if (localSaved) {
                  setDocuments(JSON.parse(localSaved));
              } else {
                  setDocuments(INITIAL_DOCS);
              }
          }
          setLoading(false);
          setIsInitialized(true);
      };

      initData();
  }, []);

  // 2. Sync Effect: Update LocalStorage AND Google Sheet on changes
  useEffect(() => {
    if (!isInitialized) return;

    // Save Local
    localStorage.setItem('btp-docs', JSON.stringify(documents));

    // Save Remote (Debounced or direct)
    const syncToSheet = async () => {
        setSyncing(true);
        await saveDocumentsToSheet(documents);
        setSyncing(false);
    };

    // We only trigger cloud sync if we have docs, to avoid wiping sheet on empty init
    if (documents.length > 0) {
        // Debounce simple pour éviter trop d'appels
        const timeoutId = setTimeout(() => {
            syncToSheet();
        }, 2000);
        return () => clearTimeout(timeoutId);
    }

  }, [documents, isInitialized]);


  const addDocument = (doc: BTPDocument) => {
    setDocuments(prev => [...prev, doc]);
  };

  const updateDocument = (updatedDoc: BTPDocument) => {
    setDocuments(prev => prev.map(d => d.id === updatedDoc.id ? updatedDoc : d));
  };

  const deleteDocument = (id: string) => {
    setDocuments(prev => prev.filter(d => d.id !== id));
    setBordereauSelectedDocs(prev => prev.filter(docId => docId !== id));
  };

  const handleNavigateToDocs = (filter: ApprovalStatus | 'ALL') => {
      setInitialDocFilter(filter);
      setActiveTab('documents');
  };

  const handleAddToBordereau = (docId: string) => {
      if (!bordereauSelectedDocs.includes(docId)) {
          setBordereauSelectedDocs(prev => [...prev, docId]);
      }
      setActiveTab('bordereaux');
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'overview':
        return <Dashboard documents={documents} onNavigateToDocs={handleNavigateToDocs} />;
      case 'documents':
        return <DocumentList 
            documents={documents} 
            onAddDocument={addDocument} 
            onUpdateDocument={updateDocument} 
            onDeleteDocument={deleteDocument}
            onNavigateToBordereau={() => setActiveTab('bordereaux')}
            onAddToBordereau={handleAddToBordereau}
            initialFilter={initialDocFilter}
        />;
      case 'bordereaux':
        return <BordereauView 
            documents={documents} 
            onAddDocument={addDocument} 
            onUpdateDocument={updateDocument} 
            onDeleteDocument={deleteDocument}
            selectedDocs={bordereauSelectedDocs}
            setSelectedDocs={setBordereauSelectedDocs}
        />;
      case 'settings':
        return <SettingsView />;
      default:
        return <Dashboard documents={documents} onNavigateToDocs={handleNavigateToDocs} />;
    }
  };

  if (loading) {
      return (
          <div className="h-screen w-screen flex flex-col items-center justify-center bg-gray-50 text-gray-500 gap-4">
              <Loader2 className="animate-spin text-blue-600" size={48} />
              <p>Synchronisation avec la base de données SBF...</p>
          </div>
      );
  }

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {syncing && (
          <div className="fixed bottom-4 right-4 bg-white/90 shadow-lg border border-blue-100 rounded-full px-4 py-2 flex items-center gap-2 text-xs font-medium text-blue-600 z-50 animate-pulse">
              <Loader2 className="animate-spin" size={12} />
              Sauvegarde Cloud...
          </div>
      )}
      {renderContent()}
    </Layout>
  );
}

import { BTPDocument } from '../types';

// Récupérer l'URL configurée dans le localStorage
const getApiUrl = () => {
    const settings = localStorage.getItem('btp-app-settings');
    if (settings) {
        const parsed = JSON.parse(settings);
        return parsed.googleScriptUrl || null;
    }
    return null;
};

export const fetchDocumentsFromSheet = async (): Promise<BTPDocument[] | null> => {
    const url = getApiUrl();
    if (!url) return null;

    try {
        const response = await fetch(url);
        const data = await response.json();
        // Le script retourne un tableau de documents
        return Array.isArray(data) ? data : [];
    } catch (error) {
        console.error("Erreur chargement Google Sheet:", error);
        return null;
    }
};

export const saveDocumentsToSheet = async (documents: BTPDocument[]): Promise<boolean> => {
    const url = getApiUrl();
    if (!url) return false;

    try {
        // IMPORTANT : Utilisation de mode: 'no-cors' 
        // Google Apps Script renvoie une redirection pour les requêtes POST, ce qui déclenche souvent
        // une erreur CORS dans le navigateur. Le mode 'no-cors' envoie la requête de manière "opaque".
        // On ne peut pas lire la réponse (status 0), mais les données sont bien reçues par le script.
        await fetch(url, {
            method: 'POST',
            mode: 'no-cors',
            headers: {
                'Content-Type': 'text/plain' // Évite le preflight (OPTIONS)
            },
            body: JSON.stringify(documents)
        });
        return true;
    } catch (error) {
        console.error("Erreur sauvegarde Google Sheet:", error);
        return false;
    }
};

